abstract class Shape
{
    public abstract double Area();
}

class Circle : Shape
{
    public double Radius;
    public Circle(double r) { Radius = r; }
    public override double Area()
    {
        return 3.14 * Radius * Radius;
    }
}

Shape s = new Circle(2);
Console.WriteLine(s.Area());

